6375   // even the values that are not available in these blocks may come from them,
6376   // and this leads to false-positive recurrence test.
6377   for (auto *Pred : predecessors(P->getParent()))
6378     if (!DT.isReachableFromEntry(Pred))
6379       return FullSet;
6380 
