6387   // that BO might be in some subloop of L, and that's completely okay.
6388   auto *L = LI.getLoopFor(P->getParent());
6389   assert(L && L->getHeader() == P->getParent());
6390   if (!L->contains(BO->getParent()))
6391     // NOTE: This bailout should be an assert instead.  However, asserting
6392     // the condition here exposes a case where LoopFusion is querying SCEV
6393     // with malformed loop information during the midst of the transform.
6394     // There doesn't appear to be an obvious fix, so for the moment bailout
6395     // until the caller issue can be fixed.  PR49566 tracks the bug.
6396     return FullSet;
6397 
6398   // TODO: Extend to other opcodes such as mul, and div
6399   switch (BO->getOpcode()) {
6400   default:
6401     return FullSet;
6402   case Instruction::AShr:
6403   case Instruction::LShr:
6404   case Instruction::Shl:
6405     break;
6406   };
