6408   if (BO->getOperand(0) != P)
6409     // TODO: Handle the power function forms some day.
6410     return FullSet;
6411 
6412   unsigned TC = getSmallConstantMaxTripCount(L);
6413   if (!TC || TC >= BitWidth)
