5912 // Try to match a control flow sequence that branches out at BI and merges back
5913 // at Merge into a "C ? LHS : RHS" select pattern.  Return true on a successful
5914 // match.
5915 static bool BrPHIToSelect(DominatorTree &DT, BranchInst *BI, PHINode *Merge,
5916                           Value *&C, Value *&LHS, Value *&RHS) {
5917   C = BI->getCondition();
5918 
5919   BasicBlockEdge LeftEdge(BI->getParent(), BI->getSuccessor(0));
5920   BasicBlockEdge RightEdge(BI->getParent(), BI->getSuccessor(1));
5921 
5922   if (!LeftEdge.isSingleEdge())
5923     return false;
5924 
5925   assert(RightEdge.isSingleEdge() && "Follows from LeftEdge.isSingleEdge()");
5926 
5927   Use &LeftUse = Merge->getOperandUse(0);
5928   Use &RightUse = Merge->getOperandUse(1);
5929 
5930   if (DT.dominates(LeftEdge, LeftUse) && DT.dominates(RightEdge, RightUse)) {
5931     LHS = LeftUse;
5932     RHS = RightUse;
5933     return true;
5934   }
5935 
5936   if (DT.dominates(LeftEdge, RightUse) && DT.dominates(RightEdge, LeftUse)) {
5937     LHS = RightUse;
5938     RHS = LeftUse;
5939     return true;
5940   }
5941 
5942   return false;
5943 }
