5961     BasicBlock *IDom = DT[PN->getParent()]->getIDom()->getBlock();
5962     assert(IDom && "At least the entry block should dominate PN");
5963 
5964     auto *BI = dyn_cast<BranchInst>(IDom->getTerminator());
5965     Value *Cond = nullptr, *LHS = nullptr, *RHS = nullptr;
