6134 static std::optional<const SCEV *>
6135 createNodeForSelectViaUMinSeq(ScalarEvolution *SE, const SCEV *CondExpr,
6136                               const SCEV *TrueExpr, const SCEV *FalseExpr) {
6137   assert(CondExpr->getType()->isIntegerTy(1) &&
6138          TrueExpr->getType() == FalseExpr->getType() &&
6139          TrueExpr->getType()->isIntegerTy(1) &&
6140          "Unexpected operands of a select.");
